css:
.loader {
  color: var(--loader-color, #8b5cf6);
  --loader-secondary-color: #c4b5fd;
  --loader-bg: #ffffff;
width: 15px;
aspect-ratio: 1;
position: relative;
}
.loader::before,
.loader::after {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
background: currentColor;
}
.loader::before {
box-shadow: -26px 0;
animation: l10-1 1.5s infinite linear;
}
.loader::after {
transform: rotate(0deg) translateX(26px);
animation: l10-2 1.5s infinite linear;
}
@keyframes l10-1 {
50%{transform:translateX(26px)}
}
@keyframes l10-2 {
100%{transform:rotate(-360deg) translateX(26px)}
}
